import{_ as e,o,c as s,a0 as a}from"./chunks/framework.CWk8AOcY.js";const r="/assets/start-battle.UKlDc_Ul.png",n="data:image/png;base64,",i="data:image/png;base64,",l="data:image/png;base64,",h="/assets/bot-info.HASw32uS.png",d="/assets/bot-directories.BmWJiLts.png",c="/assets/no-bot-directory-found.3yLukhOt.png",g="/assets/bot-root-dir-config.BiNPdCJ6.png",p="/assets/booted-bots.3S4qRKNW.png",u="/assets/waiting-for-bots-to-connect.Bz987aEY.png",m="/assets/joined-bots.B2hIptks.png",b="/assets/selected-bots.CN8BLX4v.png",A="/assets/setup-rules.BEaGGyE3.png",Q=JSON.parse('{"title":"Setting up and starting a battle","description":"","frontmatter":{},"headers":[],"relativePath":"articles/gui-battle-setup.md","filePath":"articles/gui-battle-setup.md"}'),f={name:"articles/gui-battle-setup.md"};function E(B,t,x,I,S,K){return o(),s("div",null,[...t[0]||(t[0]=[a('<h1 id="setting-up-and-starting-a-battle" tabindex="-1">Setting up and starting a battle <a class="header-anchor" href="#setting-up-and-starting-a-battle" aria-label="Permalink to &quot;Setting up and starting a battle&quot;">​</a></h1><p>This guide covers the parts of the GUI you use before a battle starts:</p><ul><li>choosing a game type</li><li>selecting and booting bots</li><li>checking which bots have joined</li><li>configuring battle rules</li><li>starting the battle in normal or paused mode</li></ul><h2 id="starting-a-battle" tabindex="-1">Starting a battle <a class="header-anchor" href="#starting-a-battle" aria-label="Permalink to &quot;Starting a battle&quot;">​</a></h2><p>The primary function of the GUI is battle creation and bot selection:</p><p><img src="'+r+'" alt="Start battle"></p><p>The window is organized into four key lists:</p><ul><li><strong>Bot Directories</strong> - available bot types from configured local directories</li><li><strong>Booted Bots</strong> - currently running bot instances launched locally</li><li><strong>Joined Bots</strong> - bots connected to the server locally or remotely</li><li><strong>Selected Bots</strong> - bots chosen for the next battle</li></ul><p>At the top, the <strong>Select game type</strong> dropdown lets you choose the <a href="./game_types.html">game type</a>, and the <strong>Setup Rules</strong> button opens the rule configuration dialog.</p><p><img src="'+n+'" alt="Setup rules and game type"></p><p>Next to the game type selector is the <strong>Recording</strong> toggle for automatic battle recording.</p><p><img src="'+i+'" alt="Auto-recording"></p><p>When enabled, each battle is recorded automatically. For details, see <a href="./gui-recording-and-replay.html">Recording and replaying battles</a>.</p><p>The <strong>Debugging</strong> group contains the <strong>Start paused</strong> toggle. When enabled, the battle enters debug mode immediately from turn 1, which is useful when you want to step through the first turns without enabling debug mode manually after the battle has started.</p><p><img src="'+l+'" alt="Debugging - Start Paused"></p><p>The bottom panel displays detailed bot information when you select entries from the <strong>Bot Directories</strong> list:</p><p><img src="'+h+'" alt="Bot Info"></p><h2 id="bot-directories" tabindex="-1">Bot Directories <a class="header-anchor" href="#bot-directories" aria-label="Permalink to &quot;Bot Directories&quot;">​</a></h2><p>The <strong>Bot Directories</strong> section lists all detected bot types from your configured local directories and shows the absolute file path for each bot.</p><p><img src="'+d+'" alt="Bot Directories"></p><p>If no directories are configured, the GUI prompts you to add at least one bot root directory:</p><p><img src="'+c+'" alt="No bot directory root"></p><p>To get started quickly, download and extract the sample bot packages, then add their parent directory through <strong>Config → Bot Root Directories</strong>.</p><p><img src="'+g+'" alt="Bot Root Directories Config"></p><p>For sample bot setup, see <a href="./installing-sample-bots.html">Installing sample bots</a>.</p><h2 id="booted-bots" tabindex="-1">Booted Bots <a class="header-anchor" href="#booted-bots" aria-label="Permalink to &quot;Booted Bots&quot;">​</a></h2><p>The <strong>Booted Bots</strong> section shows bots launched through the GUI&#39;s built-in <a href="./booter.html">booter</a>:</p><p><img src="'+p+'" alt="Booted Bots"></p><p>Multiple instances of the same bot type can be booted, which makes it easy to run battles with duplicate bot entries.</p><p>Each entry shows the bot file path and process ID. Use <strong>Boot</strong> to launch a bot process and <strong>Unboot</strong> to terminate the selected process.</p><h2 id="boot-progress-dialog" tabindex="-1">Boot progress dialog <a class="header-anchor" href="#boot-progress-dialog" aria-label="Permalink to &quot;Boot progress dialog&quot;">​</a></h2><p>When booting bots from <strong>Bot Directories</strong>, the GUI shows a progress dialog while each bot connects to the server:</p><p><img src="'+u+'" alt="Waiting for bots to connect"></p><p>The dialog shows:</p><ul><li><strong>Per-bot status</strong> for each expected bot identity</li><li><strong>Elapsed time</strong> compared with the maximum wait time</li><li>A <strong>Cancel</strong> button that aborts the boot process and kills all launched bot processes</li></ul><p>When all expected bots have connected, the dialog closes automatically and the bots appear in the <strong>Joined Bots</strong> panel.</p><p>If the timeout is reached before all bots connect, the status area is replaced with an error listing the pending bots, and <strong>Retry</strong> and <strong>Cancel</strong> buttons are shown. <strong>Retry</strong> resets the timer and continues waiting. <strong>Cancel</strong> stops all booted processes.</p><h2 id="joined-bots" tabindex="-1">Joined Bots <a class="header-anchor" href="#joined-bots" aria-label="Permalink to &quot;Joined Bots&quot;">​</a></h2><p>The <strong>Joined Bots</strong> section lists every bot connected to the server, whether local or remote:</p><p><img src="'+m+'" alt="Joined Bots"></p><p>Each entry shows the bot IP address and port, which helps distinguish between multiple instances. File paths are not shown because the server tracks WebSocket connections and bot handshake information rather than local filesystem paths.</p><h2 id="selected-bots" tabindex="-1">Selected Bots <a class="header-anchor" href="#selected-bots" aria-label="Permalink to &quot;Selected Bots&quot;">​</a></h2><p>The <strong>Selected Bots</strong> section lists the bots chosen for the upcoming battle:</p><p><img src="'+b+'" alt="Selected Bots"></p><p>The <strong>Start Battle</strong> button becomes available once the selected bots satisfy the minimum participant count defined by the current <a href="./game_types.html">game type</a>.</p><h2 id="setup-rules" tabindex="-1">Setup Rules <a class="header-anchor" href="#setup-rules" aria-label="Permalink to &quot;Setup Rules&quot;">​</a></h2><p>Customize rules for each <a href="./game_types.html">game type</a> with the <strong>Setup Rules</strong> dialog:</p><p><img src="'+A+'" alt="Setup Rules"></p><p>Available game types include <code>classic</code>, <code>melee</code>, <code>1v1</code>, and <code>custom</code>.</p><table tabindex="0"><thead><tr><th style="text-align:left;">Rule</th><th style="text-align:left;">Description</th></tr></thead><tbody><tr><td style="text-align:left;">Min. Number of Participants</td><td style="text-align:left;">The minimum number of participants required to play the battle.</td></tr><tr><td style="text-align:left;">Max. Number of Participants</td><td style="text-align:left;">The maximum number of participants allowed to play the battle.</td></tr><tr><td style="text-align:left;">Number of rounds</td><td style="text-align:left;">The number of rounds before the game ends and the results are shown.</td></tr><tr><td style="text-align:left;">Gun cooling rate</td><td style="text-align:left;">The decrease of heat per round. Higher values make the gun cool faster.</td></tr><tr><td style="text-align:left;">Max. Inactivity Turns</td><td style="text-align:left;">The number of turns allowed where no bots are hit before the remaining bots are punished by losing energy each turn.</td></tr><tr><td style="text-align:left;">Ready timeout</td><td style="text-align:left;">The maximum number of microseconds allowed before the server must receive a Bot Ready message from the bot. Otherwise, the bot is automatically kicked from the battle.</td></tr><tr><td style="text-align:left;">Turn timeout</td><td style="text-align:left;">The maximum number of microseconds allowed before the server must receive a Bot Intent message from the bot. Otherwise, the bot skips the turn. <a href="./.html" title="When a bot is skipping a turn, it is unable to change its speed or turning rates, and will continue using the speed and turn rates from the last commands successfully sent to the server.">^skip-turn</a></td></tr></tbody></table>',50)])])}const w=e(f,[["render",E]]);export{Q as __pageData,w as default};
